import { Router, Request, Response, NextFunction } from 'express';
import { z } from 'zod';
{IMPORTS}
// @archeon:endsection

// @archeon:section types
const {NAME}Schema = z.object({
  {SCHEMA_FIELDS}
});

type {NAME}Body = z.infer<typeof {NAME}Schema>;
// @archeon:endsection

// @archeon:section route
const router = Router();

router.{METHOD}('{PATH}', async (
  req: Request<{}, {}, {NAME}Body>,
  res: Response,
  next: NextFunction
) => {
  try {
    const data = {NAME}Schema.parse(req.body);

    {IMPLEMENTATION}

    res.status({SUCCESS_CODE}).json({
      success: true,
      data: {RESPONSE_DATA}
    });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return res.status(400).json({
        success: false,
        error: 'Validation failed',
        details: error.errors
      });
    }
    next(error);
  }
});
// @archeon:endsection

// @archeon:section exports
export default router;
// @archeon:endsection

