ThemeSelector.content:
// @archeon:file
// @glyph CMP:ThemeSelector
// @intent DaisyUI theme switcher dropdown with persistence
// @chain @v1 NED:theming => CMP:ThemeSelector => STO:Theme => OUT:themeApplied

// @archeon:section imports
'use client';

import { useEffect, useState } from 'react';
// @archeon:endsection

// @archeon:section component
const THEMES = [
  'light', 'dark', 'cupcake', 'emerald', 'corporate',
  'synthwave', 'retro', 'cyberpunk', 'valentine', 'halloween',
  'garden', 'forest', 'aqua', 'lofi', 'pastel',
  'fantasy', 'wireframe', 'black', 'luxury', 'dracula',
  'cmyk', 'autumn', 'business', 'acid', 'lemonade',
  'night', 'coffee', 'winter', 'dim', 'nord', 'sunset'
] as const;

export function ThemeSelector() {
  const [theme, setTheme] = useState('light');

  useEffect(() => {
    const saved = localStorage.getItem('daisyui-theme') || 'light';
    setTheme(saved);
    document.documentElement.setAttribute('data-theme', saved);
  }, []);

  const handleChange = (newTheme: string) => {
    setTheme(newTheme);
    document.documentElement.setAttribute('data-theme', newTheme);
    localStorage.setItem('daisyui-theme', newTheme);
  };

  return (
    <div className="dropdown dropdown-end">
      <div tabIndex={0} role="button" className="btn btn-ghost gap-1">
        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
            d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" />
        </svg>
        Theme
        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </div>
      <ul tabIndex={0}
        className="dropdown-content z-50 menu p-2 shadow-lg bg-base-200 rounded-box w-56 max-h-80 overflow-y-auto flex-nowrap">
        {THEMES.map((t) => (
          <li key={t}>
            <button
              className={`capitalize ${theme === t ? 'active' : ''}`}
              onClick={() => handleChange(t)}
            >
              <div className="flex gap-2 items-center">
                <div className="flex gap-0.5" data-theme={t}>
                  <span className="w-2 h-4 rounded bg-primary" />
                  <span className="w-2 h-4 rounded bg-secondary" />
                  <span className="w-2 h-4 rounded bg-accent" />
                  <span className="w-2 h-4 rounded bg-neutral" />
                </div>
                {t}
              </div>
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}
// @archeon:endsection

